import React, { Component } from 'react';
import Container from '../Container';
import TODOS from '../../mock/todos';
import TodoItem from '../TodoItem';

export default class ToDoPage extends Component {
  state = {
    todos: TODOS,
    newTodoTitle: '',
  };

  handleTodoItemClick = (itemId) => {
    this.setState((prevState) => {
      const updatedTodos = prevState.todos.map((todo) => {
        if (todo.id === itemId) {
          return { ...todo, completed: !todo.completed };
        }
        return todo;
      });
      return { todos: updatedTodos };
    });
  };

  handleInputChange = (event) => {
    this.setState({
      newTodoTitle: event.target.value,
    });
  };

  handleAddTodo = () => {
    const trimmedTitle = this.state.newTodoTitle.trim();

    if (!trimmedTitle) {
      return;
    }

    this.setState((prevState) => ({
      todos: [
        ...prevState.todos,
        {
          title: trimmedTitle,
          id: Date.now(),
          completed: false,
        },
      ],
      newTodoTitle: '',
    }));
  };

  render() {
    return (
      <div>
        <h1 className='h1 p-3 m-3 bg-purple-300 rounded-lg border border-purple-500 font-serif'>To Do List</h1>
        <section className='section border-2 mt-4'>
          <Container>
            <div className='flex gap-3 items-center flex-wrap'>
              <input
                type='text'
                value={this.state.newTodoTitle}
                onChange={this.handleInputChange}
                placeholder='Write a new todo'
                className='border rounded-lg px-3 py-2'
              />
            <button
              onClick={this.handleAddTodo}
              className='bg-purple-500 text-white px-4 py-2 rounded-lg border border-purple-700'
            >
              Add Todo
            </button>
            </div>
            <br />
            <h2>To Do List</h2>
            <div style={{ marginTop: 20 }}>
              {this.state.todos.length > 0 ? (
                this.state.todos.map((todo) => (
                  <TodoItem
                    key={todo.id}
                    {...todo}
                    onClick={() => this.handleTodoItemClick(todo.id)}
                  />
                ))
              ) : (
                <p>No todos available</p>
              )}
            </div>
          </Container>
        </section>
      </div>
    );
  }
}
